import React, { useEffect, useState, useMemo, useRef } from 'react';
import axios from 'axios';
import Header from './Header';
import * as XLSX from 'xlsx';
import { FaSearch, FaEllipsisV, FaFileExcel, FaBoxOpen, FaTags, FaBarcode, FaWeightHanging, FaMapMarkerAlt, FaCheckCircle, FaFilter, FaTimes, FaChevronDown } from 'react-icons/fa';
import { toast } from 'react-toastify';

const API_URL = 'https://rrgold.loyalstring.co.in/api/ProductMaster/GetAllLabeledStock';
const PAGE_SIZE = 15;

const Inventory = () => {
  const [activeTab, setActiveTab] = useState('labelList');
  const [deviceId, setDeviceId] = useState('');
  const [rfidDetails, setRfidDetails] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [labels, setLabels] = useState([]);
  const [search, setSearch] = useState('');
  const [filters, setFilters] = useState({});
  const [page, setPage] = useState(1);
  const searchInputRef = useRef(null);
  const [selectedRows, setSelectedRows] = useState([]);
  const [showFilter, setShowFilter] = useState(false);
  const [showExportSuccess, setShowExportSuccess] = useState(false);

  // Refs for outside click
  const filterPopupRef = useRef(null);
  const filterBtnRef = useRef(null);

  // Get userInfo from localStorage
  const [userInfo, setUserInfo] = useState({});
  useEffect(() => {
    const stored = localStorage.getItem('userInfo');
    if (stored) {
      try {
        setUserInfo(JSON.parse(stored));
      } catch {}
    }
  }, []);

  // Close filter popup on outside click
  useEffect(() => {
    if (!showFilter) return;
    function handleClick(e) {
      if (
        filterPopupRef.current &&
        !filterPopupRef.current.contains(e.target) &&
        filterBtnRef.current &&
        !filterBtnRef.current.contains(e.target)
      ) {
        setFilterAnim(false);
        setTimeout(() => setShowFilter(false), 200);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, [showFilter]);

  // Responsive helper
  const isMobile = window.innerWidth < 600;

  // Animation for filter dropdown
  const [filterAnim, setFilterAnim] = useState(false);
  const openFilter = () => { setShowFilter(true); setTimeout(() => setFilterAnim(true), 10); };
  const closeFilter = () => { setFilterAnim(false); setTimeout(() => setShowFilter(false), 200); };

  // Table header and cell styles
  const thStyle = {
    fontWeight: 700,
    color: '#222',
    background: '#f4f8ff',
    fontSize: 14,
    padding: '6px 8px',
    border: 'none',
    minWidth: 80,
    textAlign: 'left',
    verticalAlign: 'middle',
    fontFamily: 'Poppins, Inter, sans-serif',
    letterSpacing: 0.1,
    height: 36,
    whiteSpace: 'nowrap',
  };

  const tdStyle = {
    padding: '6px 8px',
    border: 'none',
    minWidth: 80,
    textAlign: 'left',
    verticalAlign: 'middle',
    fontFamily: 'Poppins, Inter, sans-serif',
    fontSize: 13,
    height: 32,
    color: '#222',
    fontWeight: 500,
    letterSpacing: 0.1,
    whiteSpace: 'nowrap',
  };

  useEffect(() => {
    if (!userInfo.ClientCode) return;
    setLoading(true);
    setError('');
    axios.post(API_URL, { ClientCode: userInfo.ClientCode })
      .then(res => {
        if (Array.isArray(res.data)) {
          setLabels(res.data);
        } else if (res.data && Array.isArray(res.data.Data)) {
          setLabels(res.data.Data);
        } else {
          setLabels([]);
        }
      })
      .catch(err => {
        setError(err.response?.data?.Message || 'Failed to fetch label list');
      })
      .finally(() => setLoading(false));
  }, [userInfo.ClientCode]);

  // Filtering and searching
  const filteredLabels = useMemo(() => {
    let data = labels;
    // Search
    if (search) {
      const s = search.toLowerCase();
      data = data.filter(l =>
        (l.ItemCode && l.ItemCode.toLowerCase().includes(s)) ||
        (l.ProductName && l.ProductName.toLowerCase().includes(s)) ||
        (l.BranchName && l.BranchName.toLowerCase().includes(s))
      );
    }
    // Column filters
    Object.entries(filters).forEach(([key, value]) => {
      if (value) {
        data = data.filter(l => (l[key] || '').toString().toLowerCase().includes(value.toLowerCase()));
      }
    });
    return data;
  }, [labels, search, filters]);

  // Pagination
  let paginatedLabels = filteredLabels;
  let totalPages = 1;
  if (!search) {
    totalPages = Math.ceil(filteredLabels.length / PAGE_SIZE);
    paginatedLabels = filteredLabels.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);
  }

  // Unique values for filters
  const getUnique = (key) => [...new Set(labels.map(l => l[key]).filter(Boolean))];

  // Handle filter change
  const handleFilterChange = (key, value) => {
    setFilters(f => ({ ...f, [key]: value }));
    setPage(1);
  };

  // Handle search change
  const handleSearchChange = (e) => {
    setSearch(e.target.value);
    setPage(1);
  };

  // Handle page change
  const handlePageChange = (newPage) => {
    if (newPage >= 1 && newPage <= totalPages) setPage(newPage);
  };

  // Export to Excel
  const handleExport = () => {
    const exportData = filteredLabels.map(({ Id, ...rest }) => rest); // Remove Id if not needed
    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Inventory');
    XLSX.writeFile(wb, 'inventory.xlsx');
    setShowExportSuccess(true);
  };

  // Selection state
  const allSelected = paginatedLabels.length > 0 && paginatedLabels.every(l => selectedRows.includes(l.Id));
  const toggleSelectAll = () => {
    if (allSelected) setSelectedRows(selectedRows.filter(id => !paginatedLabels.some(l => l.Id === id)));
    else setSelectedRows([...new Set([...selectedRows, ...paginatedLabels.map(l => l.Id)])]);
  };
  const toggleSelectRow = (id) => {
    setSelectedRows(selectedRows.includes(id) ? selectedRows.filter(i => i !== id) : [...selectedRows, id]);
  };

  // Unified filter dropdown state
  const handleFilterChangeUnified = (key, value) => {
    setFilters(f => ({ ...f, [key]: value }));
    setPage(1);
  };

  const handleGetRFIDDetails = async () => {
    if (!deviceId.trim()) {
      toast.error('Please enter a Device ID');
      return;
    }

    setLoading(true);
    try {
      const response = await fetch('https://rrgold.loyalstring.co.in/api/RFIDDevice/GetAllRFIDDetails', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ClientCode: userInfo.ClientCode,
          DeviceId: deviceId
        })
      });

      const data = await response.json();
      if (data && Array.isArray(data)) {
        setRfidDetails(data);
        toast.success('RFID details fetched successfully');
      } else {
        setRfidDetails([]);
        toast.info('No RFID details found');
      }
    } catch (error) {
      console.error('Error fetching RFID details:', error);
      toast.error('Failed to fetch RFID details');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f8f9fa 0%, #e9ecef 100%)',
      display: 'flex',
      flexDirection: 'column'
    }}>
      <Header userInfo={userInfo} />
      <div className="container py-4" style={{ maxWidth: '1400px' }}>
        <div className="card shadow-sm border-0" style={{ 
          borderRadius: '24px', 
          background: 'linear-gradient(135deg, #ffffff 0%, #f8faff 100%)',
          boxShadow: '0 8px 32px rgba(77, 101, 247, 0.07)',
          overflow: 'hidden'
        }}>
          <div className="card-body p-0">
            {/* Tabs */}
            <div className="d-flex">
              <button
                className={`btn flex-grow-1 py-3 px-4 ${activeTab === 'labelList' ? 'active' : ''}`}
                onClick={() => setActiveTab('labelList')}
                style={{
                  borderRadius: '0',
                  border: 'none',
                  background: activeTab === 'labelList' ? 'linear-gradient(90deg, #0062ff 0%, #da2f69 100%)' : '#fff',
                  color: activeTab === 'labelList' ? '#fff' : '#666',
                  fontWeight: '600',
                  fontSize: '15px',
                  transition: 'all 0.3s ease',
                  position: 'relative',
                  overflow: 'hidden'
                }}
              >
                <i className="fas fa-tags me-2"></i>
                Label List
              </button>
              <button
                className={`btn flex-grow-1 py-3 px-4 ${activeTab === 'rfidDetails' ? 'active' : ''}`}
                onClick={() => setActiveTab('rfidDetails')}
                style={{
                  borderRadius: '0',
                  border: 'none',
                  background: activeTab === 'rfidDetails' ? 'linear-gradient(90deg, #0062ff 0%, #da2f69 100%)' : '#fff',
                  color: activeTab === 'rfidDetails' ? '#fff' : '#666',
                  fontWeight: '600',
                  fontSize: '15px',
                  transition: 'all 0.3s ease'
                }}
              >
                <i className="fas fa-mobile-alt me-2"></i>
                RFID Device Details
              </button>
            </div>

            {/* Content */}
            <div className="p-4">
              {activeTab === 'labelList' ? (
                <div>
                  <h5 className="mb-4" style={{ 
                    fontSize: '20px', 
                    fontWeight: '700',
                    background: 'linear-gradient(90deg, #0062ff, #da2f69)',
                    WebkitBackgroundClip: 'text',
                    WebkitTextFillColor: 'transparent'
                  }}>Label Stock List</h5>
                  {/* Search and Buttons Row */}
                  <div className="d-flex flex-wrap align-items-center justify-content-between gap-3 mb-4">
                    <div className="position-relative flex-grow-1" style={{ maxWidth: '500px' }}>
                      <input
                        type="text"
                        placeholder="Search by Product Name, Category, SKU..."
                        value={search}
                        onChange={handleSearchChange}
                        style={{
                          width: '100%',
                          padding: '12px 20px 12px 45px',
                          borderRadius: '12px',
                          border: '1.5px solid #e5e9f2',
                          background: '#fff',
                          fontSize: '14px',
                          transition: 'all 0.3s ease',
                          boxShadow: '0 2px 10px rgba(77, 101, 247, 0.05)'
                        }}
                      />
                      <FaSearch style={{
                        position: 'absolute',
                        left: '15px',
                        top: '50%',
                        transform: 'translateY(-50%)',
                        color: '#8e9ab4',
                        fontSize: '16px'
                      }} />
                    </div>
                    <div className="d-flex gap-3">
                      <button
                        onClick={handleExport}
                        style={{
                          padding: '10px 24px',
                          borderRadius: '12px',
                          border: 'none',
                          background: 'linear-gradient(90deg, #0062ff, #da2f69)',
                          color: '#fff',
                          fontSize: '14px',
                          fontWeight: '600',
                          display: 'flex',
                          alignItems: 'center',
                          gap: '8px',
                          transition: 'all 0.3s ease',
                          boxShadow: '0 4px 15px rgba(218, 47, 105, 0.15)'
                        }}
                      >
                        <FaFileExcel /> Export to Excel
                      </button>
                      <button
                        onClick={openFilter}
                        style={{
                          padding: '10px 24px',
                          borderRadius: '12px',
                          border: '1.5px solid #e5e9f2',
                          background: '#fff',
                          color: '#0062ff',
                          fontSize: '14px',
                          fontWeight: '600',
                          display: 'flex',
                          alignItems: 'center',
                          gap: '8px',
                          transition: 'all 0.3s ease'
                        }}
                      >
                        <FaFilter /> Filter
                      </button>
                    </div>
                  </div>

                  {/* Table Container */}
                  <div style={{
                    background: '#fff',
                    borderRadius: '16px',
                    border: '1.5px solid #e5e9f2',
                    overflow: 'hidden'
                  }}>
                    <div className="table-responsive">
                      <table className="table table-hover mb-0">
                        <thead>
                          <tr style={{
                            background: 'linear-gradient(90deg, #f5f7ff, #fff)',
                            borderBottom: '1.5px solid #e5e9f2'
                          }}>
                            <th style={{ ...thStyle, width: 40 }}>Sr No</th>
                            <th style={{ ...thStyle, width: 90 }}>Item Code</th>
                            <th style={{ ...thStyle, width: 110 }}>RFID Code</th>
                            <th style={{ ...thStyle, width: 80 }}>SKU</th>
                            <th style={{ ...thStyle, minWidth: 120 }}>Product Name</th>
                            <th style={{ ...thStyle, minWidth: 90 }}>Category</th>
                            <th style={{ ...thStyle, minWidth: 90 }}>Design</th>
                            <th style={{ ...thStyle, width: 70 }}>Purity</th>
                            <th style={{ ...thStyle, width: 80 }}>Gross Wt</th>
                            <th style={{ ...thStyle, width: 80 }}>Stone Wt</th>
                            <th style={{ ...thStyle, width: 80 }}>Stone Pcs</th>
                            <th style={{ ...thStyle, width: 90 }}>Diamond Wt</th>
                            <th style={{ ...thStyle, width: 90 }}>Diamond Pcs</th>
                            <th style={{ ...thStyle, width: 80 }}>Net Wt</th>
                            <th style={{ ...thStyle, width: 70 }}>Pieces</th>
                            <th style={{ ...thStyle, width: 90 }}>Stone Amt</th>
                            <th style={{ ...thStyle, width: 110 }}>Fixed Wastage</th>
                            <th style={{ ...thStyle, width: 90 }}>Fixed Amt</th>
                            <th style={{ ...thStyle, minWidth: 90 }}>Box Name</th>
                            <th style={{ ...thStyle, minWidth: 90 }}>Vendor</th>
                            <th style={{ ...thStyle, minWidth: 90 }}>Branch</th>
                            <th style={{ ...thStyle, minWidth: 110 }}>Created Date</th>
                            <th style={{ ...thStyle, width: 110 }}>Packing Weight</th>
                            <th style={{ ...thStyle, width: 110 }}>Total Weight</th>
                            <th style={{ ...thStyle, minWidth: 80 }}>Status</th>
                          </tr>
                        </thead>
                        <tbody>
                          {paginatedLabels.map((label, idx) => (
                            <tr key={label.Id} style={{ background: idx % 2 === 0 ? '#f7f7f7' : '#fff', transition: 'background 0.2s', cursor: 'pointer', borderBottom: '1.5px solid #e0e0e0', height: 32 }}
                              onMouseOver={e => e.currentTarget.style.background = '#e6f0ff'}
                              onMouseOut={e => e.currentTarget.style.background = idx % 2 === 0 ? '#f7f7f7' : '#fff'}
                            >
                              <td style={{ ...tdStyle, width: 40, textAlign: 'center', fontWeight: 600 }}>{(page - 1) * PAGE_SIZE + idx + 1}</td>
                              <td style={{ ...tdStyle, width: 90 }}>{label.ItemCode}</td>
                              <td style={{ ...tdStyle, width: 110 }}>{label.RFIDCode}</td>
                              <td style={{ ...tdStyle, width: 80 }}>{label.SKU}</td>
                              <td style={{ ...tdStyle, minWidth: 120 }}>{label.ProductName}</td>
                              <td style={{ ...tdStyle, minWidth: 90 }}>{label.CategoryName || label.Category}</td>
                              <td style={{ ...tdStyle, minWidth: 90 }}>{label.DesignName}</td>
                              <td style={{ ...tdStyle, width: 70 }}>{label.PurityName}</td>
                              <td style={{ ...tdStyle, width: 80 }}>{label.GrossWt}</td>
                              <td style={{ ...tdStyle, width: 80 }}>{label.StoneWt}</td>
                              <td style={{ ...tdStyle, width: 80 }}>{label.StonePcs}</td>
                              <td style={{ ...tdStyle, width: 90 }}>{label.DiamondWt}</td>
                              <td style={{ ...tdStyle, width: 90 }}>{label.DiamondPcs}</td>
                              <td style={{ ...tdStyle, width: 80 }}>{label.NetWt}</td>
                              <td style={{ ...tdStyle, width: 70 }}>{label.Pieces}</td>
                              <td style={{ ...tdStyle, width: 90 }}>{label.StoneAmt}</td>
                              <td style={{ ...tdStyle, width: 110 }}>{label.FixedWastage}</td>
                              <td style={{ ...tdStyle, width: 90 }}>{label.FixedAmt}</td>
                              <td style={{ ...tdStyle, minWidth: 90 }}>{label.BoxName}</td>
                              <td style={{ ...tdStyle, minWidth: 90 }}>{label.VendorName}</td>
                              <td style={{ ...tdStyle, minWidth: 90 }}>{label.BranchName || label.Branch}</td>
                              <td style={{ ...tdStyle, minWidth: 110 }}>{label.CreatedOn ? new Date(label.CreatedOn).toLocaleDateString() : ''}</td>
                              <td style={{ ...tdStyle, width: 110 }}>{label.PackingWeight}</td>
                              <td style={{ ...tdStyle, width: 110 }}>{label.TotalWeight}</td>
                              <td style={{ ...tdStyle, minWidth: 80 }}>
                                <span className={`badge`} style={{
                                  background: label.Status === 'Active' ? '#d4f7df' : '#ffe5e5',
                                  color: label.Status === 'Active' ? '#2ecc71' : '#e74c3c',
                                  fontWeight: 700,
                                  fontSize: 12,
                                  padding: '2px 8px',
                                  borderRadius: 12,
                                  border: 'none',
                                  letterSpacing: 0.2,
                                  minWidth: 50,
                                  display: 'inline-block',
                                  textAlign: 'center',
                                  fontFamily: 'Poppins, Inter, sans-serif'
                                }}>{label.Status}</span>
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  </div>
                </div>
              ) : (
                <div>
                  <h5 className="mb-4" style={{ 
                    fontSize: '20px', 
                    fontWeight: '700',
                    background: 'linear-gradient(90deg, #0062ff, #da2f69)',
                    WebkitBackgroundClip: 'text',
                    WebkitTextFillColor: 'transparent'
                  }}>RFID Device Details</h5>
                  
                  {/* RFID Device Form */}
                  <div className="row g-3 align-items-end mb-4">
                    <div className="col-md-4">
                      <label className="form-label" style={{ 
                        fontWeight: '600',
                        fontSize: '14px',
                        color: '#4a5568'
                      }}>Device ID</label>
                      <input
                        type="text"
                        className="form-control"
                        value={deviceId}
                        onChange={(e) => setDeviceId(e.target.value)}
                        placeholder="Enter Device ID"
                        style={{
                          padding: '12px 16px',
                          borderRadius: '12px',
                          border: '1.5px solid #e5e9f2',
                          fontSize: '14px'
                        }}
                      />
                    </div>
                    <div className="col-md-4">
                      <label className="form-label" style={{ 
                        fontWeight: '600',
                        fontSize: '14px',
                        color: '#4a5568'
                      }}>Client Code</label>
                      <input
                        type="text"
                        className="form-control"
                        value={userInfo.ClientCode || ''}
                        disabled
                        style={{
                          padding: '12px 16px',
                          borderRadius: '12px',
                          border: '1.5px solid #e5e9f2',
                          background: '#f8faff',
                          fontSize: '14px'
                        }}
                      />
                    </div>
                    <div className="col-md-4">
                      <button
                        className="btn w-100"
                        onClick={handleGetRFIDDetails}
                        disabled={loading}
                        style={{
                          padding: '12px',
                          borderRadius: '12px',
                          border: 'none',
                          background: 'linear-gradient(90deg, #0062ff, #da2f69)',
                          color: '#fff',
                          fontSize: '14px',
                          fontWeight: '600',
                          transition: 'all 0.3s ease',
                          boxShadow: '0 4px 15px rgba(218, 47, 105, 0.15)'
                        }}
                      >
                        {loading ? (
                          <>
                            <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                            Loading...
                          </>
                        ) : (
                          <>
                            <i className="fas fa-search me-2"></i>
                            Get Details
                          </>
                        )}
                      </button>
                    </div>
                  </div>

                  {/* RFID Details Table */}
                  <div style={{
                    background: '#fff',
                    borderRadius: '16px',
                    border: '1.5px solid #e5e9f2',
                    overflow: 'hidden'
                  }}>
                    <div className="table-responsive">
                      <table className="table table-hover mb-0">
                        <thead>
                          <tr style={{
                            background: 'linear-gradient(90deg, #f5f7ff, #fff)',
                            borderBottom: '1.5px solid #e5e9f2'
                          }}>
                            <th style={{ padding: '16px', fontWeight: '600', fontSize: '14px', color: '#4a5568' }}>RFID Code</th>
                            <th style={{ padding: '16px', fontWeight: '600', fontSize: '14px', color: '#4a5568' }}>TID Value</th>
                            <th style={{ padding: '16px', fontWeight: '600', fontSize: '14px', color: '#4a5568' }}>Device ID</th>
                            <th style={{ padding: '16px', fontWeight: '600', fontSize: '14px', color: '#4a5568' }}>Client Code</th>
                            <th style={{ padding: '16px', fontWeight: '600', fontSize: '14px', color: '#4a5568' }}>Created On</th>
                            <th style={{ padding: '16px', fontWeight: '600', fontSize: '14px', color: '#4a5568' }}>Last Updated</th>
                            <th style={{ padding: '16px', fontWeight: '600', fontSize: '14px', color: '#4a5568' }}>Status</th>
                          </tr>
                        </thead>
                        <tbody>
                          {rfidDetails.length > 0 ? (
                            rfidDetails.map((item, index) => (
                              <tr key={item.Id || index} style={{
                                transition: 'background-color 0.2s',
                                borderBottom: '1px solid #e5e9f2'
                              }}>
                                <td style={{ padding: '16px', fontSize: '14px' }}>{item.RFIDCode}</td>
                                <td style={{ padding: '16px', fontSize: '14px' }}>{item.TIDValue}</td>
                                <td style={{ padding: '16px', fontSize: '14px' }}>{item.DeviceId}</td>
                                <td style={{ padding: '16px', fontSize: '14px' }}>{item.ClientCode}</td>
                                <td style={{ padding: '16px', fontSize: '14px' }}>
                                  {new Date(item.CreatedOn).toLocaleString()}
                                </td>
                                <td style={{ padding: '16px', fontSize: '14px' }}>
                                  {new Date(item.LastUpdated).toLocaleString()}
                                </td>
                                <td style={{ padding: '16px', fontSize: '14px' }}>
                                  <span style={{
                                    padding: '6px 12px',
                                    borderRadius: '20px',
                                    fontSize: '12px',
                                    fontWeight: '600',
                                    color: item.StatusType ? '#10b981' : '#ef4444',
                                    background: item.StatusType ? '#ecfdf5' : '#fef2f2',
                                    border: `1px solid ${item.StatusType ? '#10b98133' : '#ef444433'}`
                                  }}>
                                    {item.StatusType ? 'Active' : 'Inactive'}
                                  </span>
                                </td>
                              </tr>
                            ))
                          ) : (
                            <tr>
                              <td colSpan="7" className="text-center" style={{ padding: '32px', color: '#6b7280' }}>
                                {loading ? (
                                  <div className="d-flex align-items-center justify-content-center gap-2">
                                    <div className="spinner-border spinner-border-sm" style={{ color: '#0062ff' }} role="status">
                                      <span className="visually-hidden">Loading...</span>
                                    </div>
                                    <span>Loading RFID details...</span>
                                  </div>
                                ) : (
                                  <div className="d-flex flex-column align-items-center gap-2">
                                    <i className="fas fa-search" style={{ fontSize: '24px', color: '#9ca3af' }}></i>
                                    <span>No RFID details found</span>
                                  </div>
                                )}
                              </td>
                            </tr>
                          )}
                        </tbody>
                      </table>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
      {/* Export Success Modal */}
      {showExportSuccess && (
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: '100vw',
          height: '100vh',
          background: 'rgba(0,0,0,0.18)',
          zIndex: 9999,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}>
          <div style={{
            background: 'linear-gradient(135deg, #fff 0%, #f8f9fa 100%)',
            borderRadius: 22,
            boxShadow: '0 8px 32px #0078d422',
            padding: '2.5rem 2.5rem 2rem 2.5rem',
            minWidth: 320,
            maxWidth: 380,
            textAlign: 'center',
            fontFamily: 'Poppins, Inter, sans-serif',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: 18,
            position: 'relative',
            border: '2px solid #e0e6ed',
            overflow: 'hidden'
          }}>
            <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: 8, background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)', borderTopLeftRadius: 22, borderTopRightRadius: 22 }}></div>
            <FaCheckCircle size={48} style={{ color: 'url(#blueRedGradient)', filter: 'drop-shadow(0 2px 8px #0078d4aa)' }} />
            <svg width="0" height="0">
              <linearGradient id="blueRedGradient" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop stopColor="#0078d4" offset="0%" />
                <stop stopColor="#d60000" offset="100%" />
              </linearGradient>
            </svg>
            <div style={{ fontWeight: 700, fontSize: 22, color: '#0078d4', marginBottom: 8, background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>File exported successfully.</div>
            <button
              onClick={() => setShowExportSuccess(false)}
              style={{
                background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)',
                color: '#fff',
                border: 'none',
                borderRadius: 10,
                padding: '12px 32px',
                fontWeight: 700,
                fontSize: 16,
                cursor: 'pointer',
                boxShadow: '0 2px 12px #0078d422',
                marginTop: 8,
                fontFamily: 'Poppins, Inter, sans-serif',
                transition: 'background 0.2s, transform 0.2s',
              }}
              onMouseOver={e => {
                e.currentTarget.style.background = 'linear-gradient(90deg, #d60000 0%, #0078d4 100%)';
                e.currentTarget.style.transform = 'scale(1.04)';
              }}
              onMouseOut={e => {
                e.currentTarget.style.background = 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)';
                e.currentTarget.style.transform = 'scale(1)';
              }}
            >
              Close
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Inventory;
